func StartWorkers(ctx context.Context, jobs <-chan Job, n int, wg *sync.WaitGroup) {
    for i := 0; i < n; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for { select { case j, ok := <-jobs: if !ok { return }; processJob(j); case <-ctx.Done(): return } }
        }()
    }
}

